"use client";

import { useEffect, useRef } from "react";

const LINE_COUNT = 52;
const FILL_RATIO = 0.28;
const MIN_THICKNESS = 0.45;
const PEAK_X_FRAC = 0.3;
const PEAK_Y_FRAC = 0.3;
const PEAK_AMP_FRAC = 0.34;
const SIGMA_X_FRAC = 0.32;
const SIGMA_Y_FRAC = 0.28;
const SAMPLE_STEP = 2;

function gauss2D(
  x: number,
  y: number,
  cx: number,
  cy: number,
  sx: number,
  sy: number,
) {
  const dx = (x - cx) / sx;
  const dy = (y - cy) / sy;
  return Math.exp(-(dx * dx + dy * dy) / 2);
}

function draw(canvas: HTMLCanvasElement) {
  const ctx = canvas.getContext("2d")!;
  const dpr = window.devicePixelRatio || 1;
  const rect = canvas.getBoundingClientRect();

  canvas.width = rect.width * dpr;
  canvas.height = rect.height * dpr;
  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);

  const w = rect.width;
  const h = rect.height;

  const styles = getComputedStyle(canvas);
  const bg = styles.getPropertyValue("--background").trim();
  const fg = styles.getPropertyValue("--foreground").trim();

  ctx.fillStyle = bg;
  ctx.fillRect(0, 0, w, h);

  const cx = PEAK_X_FRAC * w;
  const cy = PEAK_Y_FRAC * h;
  const sx = SIGMA_X_FRAC * w;
  const sy = SIGMA_Y_FRAC * h;
  const amp = PEAK_AMP_FRAC * h;
  const spacing = h / (LINE_COUNT + 1);

  const lineYAt = (i: number, x: number) => {
    const baseY = spacing * (i + 1);
    return baseY + amp * gauss2D(x, baseY, cx, cy, sx, sy);
  };

  ctx.fillStyle = fg;

  for (let i = 0; i < LINE_COUNT; i++) {
    ctx.beginPath();

    const top: [number, number][] = [];
    const bot: [number, number][] = [];

    for (let x = 0; x <= w; x += SAMPLE_STEP) {
      const y = lineYAt(i, x);
      const yAbove = i > 0 ? lineYAt(i - 1, x) : y - spacing;
      const yBelow = i < LINE_COUNT - 1 ? lineYAt(i + 1, x) : y + spacing;
      const gap = Math.min(y - yAbove, yBelow - y);
      const thickness = Math.max(MIN_THICKNESS, gap * FILL_RATIO);

      top.push([x, y - thickness / 2]);
      bot.push([x, y + thickness / 2]);
    }

    ctx.moveTo(top[0][0], top[0][1]);
    for (let k = 1; k < top.length; k++) ctx.lineTo(top[k][0], top[k][1]);
    for (let k = bot.length - 1; k >= 0; k--) ctx.lineTo(bot[k][0], bot[k][1]);
    ctx.closePath();
    ctx.fill();
  }
}

export function FlowField() {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current!;
    draw(canvas);

    const onResize = () => draw(canvas);
    window.addEventListener("resize", onResize);
    return () => window.removeEventListener("resize", onResize);
  }, []);

  return (
    <canvas
      ref={canvasRef}
      style={{ width: "100%", height: "100%", display: "block" }}
    />
  );
}

